#!/usr/bin/env python3
"""
Test for multi-language support in code_search.py
Tests Rust, Java, Go, and Haskell pattern matching and fixes.
"""

import json
import os
import sys
import tempfile
import subprocess
from pathlib import Path

def run_test():
    """Run tests for all new languages."""

    # Create test files
    test_files = {
        'main.rs': 'fn main() { println!("hi {}", 42); }',
        'Main.java': 'class Main { static void main(String[] a){ System.out.println("hi"); } }',
        'main.go': 'package main\nimport "log"\nfunc main() { log.Println("hi", 42) }',
        'Main.hs': 'module Main where\nmain = putStrLn "hi"',
    }

    # Test rules
    test_rules = [
        {
            "id": "go-no-log-println",
            "kind": "pattern",
            "languages": ["go"],
            "pattern": "log.Println($ARGS)",
            "fix": {
                "kind": "replace",
                "template": "logger.Println$ARGS"
            }
        },
        {
            "id": "rust-no-println-macro",
            "kind": "pattern",
            "languages": ["rust"],
            "pattern": "println!($MSG)",
            "fix": {
                "kind": "replace",
                "template": "log::info!$MSG"
            }
        },
        {
            "id": "java-no-system-out",
            "kind": "pattern",
            "languages": ["java"],
            "pattern": "System.out.println($X)",
            "fix": {
                "kind": "replace",
                "template": "logger.info($X)"
            }
        },
        {
            "id": "hs-avoid-putStrLn",
            "kind": "pattern",
            "languages": ["haskell"],
            "pattern": "putStrLn $MSG",
            "fix": {
                "kind": "replace",
                "template": "logInfo $MSG"
            }
        }
    ]

    # Create temporary directory
    with tempfile.TemporaryDirectory() as tmpdir:
        # Write test files
        for filename, content in test_files.items():
            filepath = Path(tmpdir) / filename
            filepath.write_text(content)

        # Write rules file
        rules_path = Path(tmpdir) / 'rules.json'
        rules_path.write_text(json.dumps(test_rules))

        # Run code_search.py
        env = os.environ.copy()
        env['PYTHONPATH'] = '/workspace/.venv/lib/python3.12/site-packages'

        result = subprocess.run(
            ['python3', '/workspace/code_search.py', tmpdir, '--rules', str(rules_path), '--dry-run'],
            capture_output=True,
            text=True,
            env=env
        )

        # Parse output
        lines = [line for line in result.stdout.strip().split('\n') if line]
        outputs = [json.loads(line) for line in lines]

        # Verify we got matches for all languages
        languages_found = set()
        for output in outputs:
            if 'language' in output:
                languages_found.add(output['language'])

        expected_languages = {'rust', 'java', 'go', 'haskell'}
        if languages_found != expected_languages:
            print(f"ERROR: Expected languages {expected_languages}, got {languages_found}")
            return False

        # Verify fixes
        fix_outputs = [o for o in outputs if o.get('event') == 'fix']
        if len(fix_outputs) != 4:
            print(f"ERROR: Expected 4 fix events, got {len(fix_outputs)}")
            return False

        # Verify all fixes have applied=True
        for fix in fix_outputs:
            if not fix.get('applied'):
                print(f"ERROR: Fix not applied: {fix}")
                return False

        # Verify replacements
        for fix in fix_outputs:
            if fix['rule_id'] == 'go-no-log-println':
                if fix['replacement'] != 'logger.Println("hi", 42)':
                    print(f"ERROR: Wrong Go replacement: {fix['replacement']}")
                    return False
            elif fix['rule_id'] == 'rust-no-println-macro':
                if fix['replacement'] != 'log::info!("hi {}", 42)':
                    print(f"ERROR: Wrong Rust replacement: {fix['replacement']}")
                    return False
            elif fix['rule_id'] == 'java-no-system-out':
                if fix['replacement'] != 'logger.info("hi")':
